diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..c5c6b9e37e42 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1516,6 +1516,7 @@ static Instruction *foldBoxMultiply(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Value *V = simplifyAddInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -1778,12 +1779,35 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   // (add (add A, 1), (sext (icmp ne A, 0))) => call umax(A, 1)
   if (match(LHS, m_Add(m_Value(A), m_One())) &&
       match(RHS, m_OneUse(m_SExt(m_OneUse(m_SpecificICmp(
-                     ICmpInst::ICMP_NE, m_Specific(A), m_ZeroInt())))))) {
+                     CmpInst::ICMP_NE, m_Specific(A), m_ZeroInt())))))) {
     Value *OneConst = ConstantInt::get(A->getType(), 1);
     Value *UMax = Builder.CreateBinaryIntrinsic(Intrinsic::umax, A, OneConst);
     return replaceInstUsesWith(I, UMax);
   }

+  // Transform ceiling division pattern:
+  // (x >> C) + (zext ((x & Mask) != 0)) --> (x + Mask) >> C
+  // where Mask = (1 << C) - 1
+  {
+    Value *X;
+    const APInt *C, *Mask;
+    // Match (x >> C) + zext((x & Mask) != 0)
+    if (match(&I, m_c_BinOp(m_OneUse(m_LShr(m_Value(X), m_APInt(C))),
+                            m_OneUse(m_ZExt(
+                                m_OneUse(m_ICmp(ICmpInst::ICMP_NE,
+                                                m_And(m_Deferred(X),
+                                                      m_APInt(Mask)),
+                                                m_ZeroInt())))))) &&
+        *Mask == APInt::getLowBitsSet(C->getBitWidth(), C->getZExtValue())) {
+      Value *MaskVal = ConstantInt::get(X->getType(), *Mask);
+      Value *Add = Builder.CreateAdd(X, MaskVal, "", I.hasNoUnsignedWrap(),
+                                     I.hasNoSignedWrap());
+      return BinaryOperator::CreateLShr(Add, ConstantInt::get(X->getType(), *C));
+    }
+    // Also match commutative version: zext((x & Mask) != 0) + (x >> C)
+    // The m_c_BinOp already handles commutativity, so no additional code needed.
+  }
+
   if (Instruction *Ashr = foldAddToAshr(I))
     return Ashr;

@@ -1893,6 +1917,7 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Eliminate an op from a linear interpolation (lerp) pattern.
 static Instruction *factorizeLerp(BinaryOperator &I,
                                   InstCombiner::BuilderTy &Builder) {
